const input = $input.first().json;
const action = input.action || 'list_tasks';

const SUPABASE_URL = '{{SUPABASE_URL}}';
const SUPABASE_KEY = '{{SUPABASE_SERVICE_KEY}}';
const pgHeaders = {
  'apikey': SUPABASE_KEY,
  'Authorization': 'Bearer ' + SUPABASE_KEY
};

const creds = await helpers.httpRequest({
  method: 'GET',
  url: SUPABASE_URL + '/rest/v1/template_credentials?template_id=eq.todoist&cred_key=eq.todoist_token&select=cred_value',
  headers: pgHeaders
});

if (!creds || creds.length === 0 || !creds[0].cred_value) {
  return [{ json: { error: 'Todoist API token not configured. Use add_credential to set it up.' } }];
}

const token = creds[0].cred_value;
const API_BASE = 'https://api.todoist.com/api/v1';
const apiHeaders = {
  'Authorization': 'Bearer ' + token,
  'Content-Type': 'application/json'
};

const priorityLabels = { 1: '', 2: ' [P3]', 3: ' [P2]', 4: ' [P1]' };

function formatTask(t) {
  let line = '- ' + t.content;
  if (t.priority > 1) line += priorityLabels[t.priority] || '';
  if (t.due) {
    line += ' (due: ' + (t.due.date || '') + ')';
  }
  if (t.labels && t.labels.length > 0) line += ' [' + t.labels.join(', ') + ']';
  if (t.description) line += '\n  ' + t.description.substring(0, 100);
  return line;
}

// === list_tasks ===
if (action === 'list_tasks') {
  try {
    let url = API_BASE + '/tasks';
    const params = [];
    if (input.project_id) params.push('project_id=' + input.project_id);
    if (input.filter) params.push('filter=' + encodeURIComponent(input.filter));
    if (params.length > 0) url += '?' + params.join('&');

    const resp = await helpers.httpRequest({ method: 'GET', url, headers: apiHeaders });
    const tasks = resp.results || [];

    if (tasks.length === 0) {
      return [{ json: { result: 'No tasks found.' } }];
    }

    let result = 'Tasks (' + tasks.length + '):\n\n';
    for (const t of tasks.slice(0, 20)) {
      result += formatTask(t) + '\n  ID: ' + t.id + '\n\n';
    }
    if (tasks.length > 20) result += '(' + (tasks.length - 20) + ' more tasks not shown)';

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list tasks: ' + err.message } }];
  }

// === create_task ===
} else if (action === 'create_task') {
  const content = input.content;
  if (!content) return [{ json: { error: 'Parameter "content" is required (task title).' } }];

  try {
    const body = { content };
    if (input.description) body.description = input.description;
    if (input.due_string) body.due_string = input.due_string;
    if (input.priority) body.priority = parseInt(input.priority) || 1;
    if (input.project_id) body.project_id = input.project_id;
    if (input.labels) body.labels = input.labels.split(',').map(l => l.trim());

    const task = await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/tasks',
      headers: apiHeaders,
      body: JSON.stringify(body)
    });

    const parsed = typeof task === 'string' ? JSON.parse(task) : task;
    let result = 'Task created: ' + parsed.content;
    if (parsed.due) result += ' (due: ' + parsed.due.date + ')';
    result += '\nID: ' + parsed.id;

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to create task: ' + err.message } }];
  }

// === complete_task ===
} else if (action === 'complete_task') {
  const taskId = input.task_id;
  if (!taskId) return [{ json: { error: 'Parameter "task_id" is required.' } }];

  try {
    await helpers.httpRequest({
      method: 'POST',
      url: API_BASE + '/tasks/' + taskId + '/close',
      headers: apiHeaders
    });
    return [{ json: { result: 'Task ' + taskId + ' marked as completed.' } }];
  } catch (err) {
    return [{ json: { error: 'Failed to complete task: ' + err.message } }];
  }

// === list_projects ===
} else if (action === 'list_projects') {
  try {
    const resp = await helpers.httpRequest({
      method: 'GET',
      url: API_BASE + '/projects',
      headers: apiHeaders
    });
    const projects = resp.results || [];

    if (projects.length === 0) {
      return [{ json: { result: 'No projects found.' } }];
    }

    let result = 'Projects (' + projects.length + '):\n\n';
    for (const p of projects) {
      result += '- **' + p.name + '** (ID: ' + p.id + ')';
      if (p.is_favorite) result += ' [favorite]';
      result += '\n';
    }

    return [{ json: { result } }];
  } catch (err) {
    return [{ json: { error: 'Failed to list projects: ' + err.message } }];
  }

} else {
  return [{ json: { error: 'Unknown action: ' + action + '. Use list_tasks, create_task, complete_task, or list_projects.' } }];
}
